actions.script:
import org.moqui.context.ExecutionContext
import org.moqui.impl.context.UserFacadeImpl.UserInfo

ExecutionContext ec = context.ec

// Permissions are handled by Moqui's artifact authorization system
// Users must be in appropriate groups (McpUser, MCP_BUSINESS) with access to McpServices artifact group

// Authentication is handled by MoquiAuthFilter - user context is already set
// No need to re-validate session ownership here
ec.artifactExecution.disableAuthz()

ec.logger.info("MCP Initialize for session ${sessionId}, user ${ec.user.userId}")

// Validate protocol version - support common MCP versions with version negotiation
def supportedVersions = ["2025-11-25", "2025-06-18", "2024-11-05", "2024-10-07", "2023-06-05"]
if (!supportedVersions.contains(protocolVersion)) {
    throw new Exception("Unsupported protocol version: ${protocolVersion}. Supported versions: ${supportedVersions.join(', ')}")
}

// Get current user context (if authenticated)
def userId = ec.user.userId
def userAccountId = userId ? userId : null

// Try to load root instructions from wiki
def instructions = null
try {
    def wikiPage = ec.entity.find("moqui.resource.wiki.WikiPage")
        .condition("wikiSpaceId", "MCP_SERVICE_DOCS")
        .condition("pagePath", "root")
        .useCache(true)
        .one()

    if (wikiPage) {
        def wikiSpace = ec.entity.find("moqui.resource.wiki.WikiSpace")
            .condition("wikiSpaceId", wikiPage.wikiSpaceId)
            .one()

        if (wikiSpace) {
            def pageLocation = wikiSpace.rootPageLocation
            if (!pageLocation.endsWith('/')) pageLocation += '/'
            pageLocation += wikiPage.pagePath + '.md'

            def pageRef = ec.resource.getLocationReference(pageLocation)
            def wikiText = pageRef?.getText()
            if (wikiText) {
                instructions = wikiText
                ec.logger.info("MCP Initialize: Loaded root instructions from wiki")
            }
        }
    }
} catch (Exception e) {
    ec.logger.debug("Could not load root instructions from wiki: ${e.message}")
}

// Fallback to hardcoded instructions if wiki not available
if (!instructions) {
    def restHint = " For read-only data inspection / debugging, use moqui_rest_call (GET-only) to query any entity (e1/{Entity}, m1/{Entity}/{master}) and the s1/moqui / s1/mantle REST APIs; discover schemas via service.swagger/*.json and entity.swagger. SystemSupport only."
    instructions = "This server provides access to GrowERP through MCP. Use moqui_search_services to find available services, moqui_get_service_details to learn required parameters, and moqui_execute_service to run them. Multi-step business processes are documented as workflows: fetch them with moqui_get_help(uri='wiki:workflow:<Name>')." + restHint
}

// Build server capabilities - don't fetch actual tools/resources during init
// Tools and resources will be discovered via separate list requests per MCP spec
def serverCapabilities = [
    tools: [listChanged: true],
    resources: [subscribe: true, listChanged: true],
    logging: [:]
]

// Build server info with useful metadata
def moquiVersion = ec.factory.moquiVersion ?: "Unknown"
def runtimePath = ec.factory.runtimePath ?: "Unknown"

// Get hostname and IP
def hostname = "Unknown"
def ipAddress = "Unknown"
try {
    def localhost = java.net.InetAddress.getLocalHost()
    hostname = localhost.getHostName()
    ipAddress = localhost.getHostAddress()
} catch (Exception e) { /* ignore */ }

// Get Java/JVM info
def javaVersion = System.getProperty("java.version") ?: "Unknown"
def javaVendor = System.getProperty("java.vendor") ?: "Unknown"

// Get server start time from Runtime MXBean
def serverStartTime = null
try {
    def runtimeMXBean = java.lang.management.ManagementFactory.getRuntimeMXBean()
    serverStartTime = runtimeMXBean.getStartTime()
} catch (Exception e) { /* ignore */ }

def serverInfo = [
    name: "Moqui MCP Server",
    version: "2.1.0",
    moquiVersion: moquiVersion,
    hostname: hostname,
    ipAddress: ipAddress,
    javaVersion: javaVersion,
    javaVendor: javaVendor,
    serverStartTime: serverStartTime,
    runtimePath: runtimePath,
    currentUser: ec.user?.username,
    currentUserId: ec.user?.userId
]

result = [
    protocolVersion: context.protocolVersion ?: "2024-11-05",
    capabilities: serverCapabilities,
    serverInfo: serverInfo,
    sessionId: sessionId,
    instructions: instructions
]

ec.logger.info("MCP Initialize for user ${userId} (session ${sessionId}): capabilities negotiated")

import org.moqui.context.ExecutionContext
import groovy.json.JsonBuilder

ExecutionContext ec = context.ec

// Start timing for execution metrics
def startTime = System.currentTimeMillis()
def isError = false

// ── Agent trust gate ──────────────────────────────────────────────
// Before executing ANY arbitrary Moqui service on behalf of an agent,
// ask moqui-adk's governance service to classify/scope/pin-tenant the
// call. The hook is optional: when moqui-adk is not installed the gate
// is a no-op and MCP behaves exactly as before.
def GOV_SVC = "AdkGovernanceServices.govern#AgentAction"
def REC_SVC = "AdkGovernanceServices.record#AgentResult"
// Tool calls dispatch on a detached worker thread with no HttpServletRequest,
// so the agent identity captured at SSE-connect is resolved by MCP sessionId.
def adkHdrs = null
try { adkHdrs = org.moqui.mcp.EnhancedMcpServlet.getAdkHeaders(sessionId) } catch (ignore) {}
def resolveAdkConfigId = {
    String cid = null
    try { cid = ec.web?.getRequest()?.getHeader('adk_config_id') } catch (ignore) {}
    if (!cid) cid = arguments?._adkConfigId
    if (!cid) cid = adkHdrs?.configId
    return cid
}
// Tenant owner fallback: the general per-tenant interactive agent has no
// AdkAgentConfig row, so it sends the owner directly via this header.
def resolveAdkOwner = {
    String o = null
    try { o = ec.web?.getRequest()?.getHeader('adk_owner_party_id') } catch (ignore) {}
    if (!o) o = arguments?._adkOwnerPartyId
    if (!o) o = adkHdrs?.owner
    return o
}
// returns [allowed:bool, decision:String, args:Map, logId:String, message:String]
def applyGate = { String svcName, Map svcArgs ->
    if (!ec.service.isServiceDefined(GOV_SVC)) return [allowed: true, args: svcArgs, logId: null]
    def gov = ec.service.sync().name(GOV_SVC).parameters([
            configId: resolveAdkConfigId(), toolName: name, serviceName: svcName,
            parameters: svcArgs, adkSessionId: sessionId]).call()
    return [allowed: (gov?.decision == 'allowed'), decision: gov?.decision,
            args: (gov?.parameters ?: svcArgs), logId: gov?.adkActionLogId,
            message: gov?.message]
}
def recordResult = { logId, res ->
    if (logId && ec.service.isServiceDefined(REC_SVC))
        ec.service.sync().name(REC_SVC).parameters([adkActionLogId: logId,
            resultSummary: new groovy.json.JsonBuilder(res).toString()]).call()
}
// Closest real growerp.* service names for a bad/guessed name → recovery hint.
def suggestVerbs = ['get','create','update','delete','find','store','check','send',
    'run','register','login','logout','search','submit','receive','reset','close',
    'recalculate','list','add','remove','ingest','push','ensure','escalate','reply',
    'process','set','calculate','validate','approve','cancel','complete','draft',
    'generate','publish','mark','test','start','pause'] as Set
// Domain aliases: some list/read operations live on a generic service whose
// NAME lacks the domain noun — orders, invoices, shipments, payments and
// transactions are all "FinDoc", listed via FinDocServices100.get#FinDoc. A
// name-only search/suggest can't find them, so map those nouns → the real service.
def finDocTerms = ['order','invoice','shipment','payment','transaction',
    'findoc','financial document'] as Set
def domainAliasFor = { String q ->
    if (!q) return []
    def low = q.toLowerCase()
    finDocTerms.any { low.contains(it) }
        ? ['growerp.100.FinDocServices100.get#FinDoc'] : []
}
def suggestServices = { String badName, int max ->
    if (!badName) return []
    def aliases = domainAliasFor(badName)
    def names = org.moqui.mcp.adapter.McpToolAdapter.getCachedGroWerpServiceNames(ec)
    // tokens from the tail (after last '.'), camelCase-split, drop '#', lowercase
    def tail = badName.contains('.') ? badName.substring(badName.lastIndexOf('.') + 1) : badName
    def raw = tail.replace('#',' ')
        .replaceAll(/([a-z])([A-Z])/, '$1 $2')
        .toLowerCase().split(/\s+/).findAll { it.length() > 2 } as List
    // prefer noun tokens; verbs like get/create match too many services and add noise
    def nouns = raw.findAll { !suggestVerbs.contains(it) }
    def base = (nouns ?: raw) as List
    // add singular forms so 'orders' matches 'Order'
    def toks = (base + base.findAll { it.endsWith('s') && it.length() > 3 }.collect { it[0..-2] }) as Set
    if (!toks) return []
    def scored = names.collect { n ->
            def low = n.toLowerCase()
            [name: n, score: toks.count { low.contains(it) }]
        }
        .findAll { it.score > 0 }
        .sort { -it.score }
        .collect { it.name }
    // Surface domain-alias services (e.g. get#FinDoc for 'order') first.
    (aliases + scored.findAll { !aliases.contains(it) }).take(max)
}
// Fix up common LLM service-name mistakes; returns the resolved name or the
// original (still-undefined) name so the caller's error path can suggest.
// Unique growerp.* service whose name ends with ".verb#Noun", or null.
def uniqueByTail = { String tail ->
    def suffix = ('.' + tail).toLowerCase()
    def matches = org.moqui.mcp.adapter.McpToolAdapter.getCachedGroWerpServiceNames(ec)
        .findAll { it.toLowerCase().endsWith(suffix) }
    matches.size() == 1 ? matches[0] : null
}
def resolveSvcName = { String svcName ->
    if (!svcName) return svcName
    // Short "verb#Noun" without package path: resolve to the unique growerp.*
    // service if there is one. Checked BEFORE isServiceDefined because Moqui
    // reports create/update/delete/store#<Entity> as defined (implicit
    // entity-auto), which would bypass the real growerp service.
    if (svcName.contains('#') && svcName.indexOf('.') < 0) {
        def resolved = uniqueByTail(svcName)
        if (resolved) {
            ec.logger.info("MCP: resolved short service name '${svcName}' → '${resolved}'")
            return resolved
        }
        return svcName
    }
    if (ec.service.isServiceDefined(svcName)) return svcName
    // Full-looking name with the WRONG package path (LLMs guess the service
    // file): resolve by the verb#Noun tail if it names exactly one service.
    if (svcName.contains('#')) {
        def tail = svcName.substring(svcName.lastIndexOf('.') + 1)
        if (tail.contains('#')) {
            def resolved = uniqueByTail(tail)
            if (resolved) {
                ec.logger.info("MCP: resolved wrong-package service name '${svcName}' → '${resolved}'")
                return resolved
            }
        }
        return svcName
    }
    // Missing '#' separator: "OrderServices.getSalesOrders" → "OrderServices.get#SalesOrders"
    if (!svcName.contains('#')) {
        def lastDot = svcName.lastIndexOf('.')
        if (lastDot > 0) {
            def tail = svcName.substring(lastDot + 1)
            for (v in suggestVerbs) {
                if (tail.startsWith(v) && tail.length() > v.length() &&
                        Character.isUpperCase(tail.charAt(v.length()))) {
                    def corrected = svcName.substring(0, lastDot + 1) +
                        v + '#' + tail.substring(v.length())
                    if (ec.service.isServiceDefined(corrected)) {
                        ec.logger.info("MCP: auto-corrected service name '${svcName}' → '${corrected}'")
                        return corrected
                    }
                }
            }
        }
    }
    return svcName
}
// A failed nested sync service call does NOT throw into this script: Moqui
// puts the error on the message facade and call() returns null. Left alone,
// the facade error marks ToolsCall itself failed and the client gets {}.
// Call this right after a nested call to surface the error as an MCP result.
def errorResultIfFailed = { ->
    if (!ec.message.hasError()) return null
    def errText = ec.message.getErrorsString()?.trim()
    ec.message.clearErrors()
    isError = true
    return [content: [[type: "text", text: "Error executing tool ${name}: ${errText}"]], isError: true]
}

try {
    // Consolidated Tool Dispatching

    ec.logger.info("MCP ToolsCall: Dispatching tool name=${name}, arguments=${arguments}")
    ec.logger.info("MCP ToolsCall: CODE VERSION: 2025-01-09 - FIXED NULL CHECK")

    // Moqui screens are not used in GrowERP (Flutter frontend); screen
    // browsing/rendering tools were removed. Point agents at the service tools.
    def removedScreenTools = ["moqui_browse_screens", "moqui_render_screen", "moqui_search_screens", "moqui_get_screen_details"] as Set
    if (removedScreenTools.contains(name)) {
        result = [content: [[type: "text", text: "Moqui screens are not used in this GrowERP deployment; screen tools are not available. Use moqui_search_services, moqui_get_service_details, moqui_execute_service and moqui_rest_call instead."]], isError: true]
        return
    }

    // Handle internal discovery/utility tools
    def internalToolMappings = [
        "moqui_get_help": "McpServices.mcp#GetHelp",
        "moqui_prompts_list": "McpServices.mcp#PromptsList",
        "moqui_prompts_get": "McpServices.mcp#PromptsGet",
        "moqui_rest_call": "McpServices.mcp#RestCall"
    ]

    def targetServiceName = internalToolMappings[name]
    if (targetServiceName) {
        def serviceResult = ec.service.sync().name(targetServiceName).parameters(arguments ?: [:])
            .requireNewTransaction(true).call()
        def callErr = errorResultIfFailed()
        if (callErr != null) { result = callErr; return }
        def actualRes = serviceResult?.result ?: serviceResult
        // Ensure standard MCP response format with content array
        if (actualRes instanceof Map && actualRes.content && actualRes.content instanceof List) {
            result = actualRes
        } else {
            result = [ content: [[type: "text", text: new groovy.json.JsonBuilder(actualRes).toString()]], isError: false ]
        }
        return
     }

    if (name == "moqui_execute_service") {
        def svcName = resolveSvcName(arguments?.serviceName)
        def svcArgs = arguments?.parameters ?: [:]
        if (!svcName || !ec.service.isServiceDefined(svcName)) {
            def sugg = suggestServices(svcName, 5)
            def hint = sugg ? " Did you mean: ${sugg.join(', ')}?"
                : " Use moqui_search_services to find valid names."
            throw new Exception("Unknown service name: ${svcName}. Only growerp.* services are callable.${hint}")
        }
        // isServiceDefined is also true for implicit entity-auto CRUD
        // (create/update/delete/store#<Entity>) — all writes, no defined
        // service. Entity writes must go through a growerp.* service; reads
        // are available via the read-only moqui_rest_call e1/ API.
        if (ec.service.getServiceDefinition(svcName) == null) {
            def sugg = suggestServices(svcName, 5)
            def hint = sugg ? " Did you mean: ${sugg.join(', ')}?"
                : " Use moqui_search_services to find valid names."
            throw new Exception("Direct entity write '${svcName}' is not allowed. Use a growerp.* service for writes, or moqui_rest_call (e1/) for reads.${hint}")
        }
        def gate = applyGate(svcName, svcArgs)
        if (!gate.allowed) {
            // blocked → error to the agent; pending → not an error, just queued
            result = [content: [[type: "text", text: gate.message ?: "Action not permitted"]],
                      isError: (gate.decision == 'blocked')]
            return
        }
        def serviceResult = ec.service.sync().name(svcName).parameters(gate.args)
            .requireNewTransaction(true).call()
        def callErr = errorResultIfFailed()
        if (callErr != null) { result = callErr; return }
        recordResult(gate.logId, serviceResult)
        result = [content: [[type: "text", text: new groovy.json.JsonBuilder(serviceResult).toString()]], isError: false]
        return
    }

    if (name == "searchKnowledge") {
        // Resolve the calling agent's tenant (same configId→owner path as the
        // governance gate), search the owner's knowledge base, and audit it.
        def cid = resolveAdkConfigId()
        def owner = null
        if (cid) {
            def cfg = ec.entity.find('moqui.adk.AdkAgentConfig')
                    .condition('adkAgentConfigId', cid).disableAuthz().one()
            owner = cfg?.ownerPartyId
        }
        // Fallback for the general per-tenant interactive agent (no config row).
        if (!owner) owner = resolveAdkOwner()
        def kSvc = "AdkKnowledgeServices.search#AdkKnowledge"
        if (!owner || !ec.service.isServiceDefined(kSvc)) {
            result = [content: [[type: "text", text: "No company knowledge base is available in this context."]], isError: true]
            return
        }
        def kRes = ec.service.sync().name(kSvc).parameters([
                ownerPartyId: owner, query: arguments?.query,
                limit: (arguments?.limit ?: 5)]).call()
        def rows = kRes?.results ?: []
        def txt = rows.isEmpty() ? "No matching company knowledge found." :
                rows.collect { "• ${it.title ? (it.title + ': ') : ''}${it.text}" }.join("\n\n")
        // Audit (read) — best effort, mirrors the governance log.
        try {
            if (ec.service.isServiceDefined("create#moqui.adk.AdkActionLog"))
                ec.service.sync().name("create#moqui.adk.AdkActionLog").parameters([
                    ownerPartyId: owner, configId: cid, toolName: 'searchKnowledge',
                    serviceName: kSvc, verbClass: 'read', decision: 'allowed',
                    argsJson: new groovy.json.JsonBuilder(arguments ?: [:]).toString(),
                    resultSummary: "${rows.size()} passage(s)", actionTime: ec.user.nowTimestamp]).call()
        } catch (Exception ignore) {}
        result = [content: [[type: "text", text: txt]], isError: false]
        return
    }

    if (name == "okf_index" || name == "okf_load_concept" || name == "okf_follow") {
        // OKF (Open Knowledge Format) bundle navigation: curated stable domain
        // knowledge hosted under a WikiSpace (default GROWERP_OKF). Progressive
        // disclosure: index -> load_concept -> follow. Per the OKF spec the
        // consumer tolerates broken links, unknown types and missing fields.
        String spaceId = (arguments?.wikiSpaceId ?: "GROWERP_OKF") as String
        def okfSpace = ec.entity.find("moqui.resource.wiki.WikiSpace")
                .condition("wikiSpaceId", spaceId).useCache(true).one()
        if (okfSpace == null) {
            result = [content: [[type: "text", text: "No OKF bundle found (wiki space '${spaceId}' does not exist). Run the OKF export first (growerp.100.OkfServices100.export#OkfBundle)."]], isError: true]
            return
        }
        String rootLoc = okfSpace.rootPageLocation
        String bundleDirLoc = rootLoc.endsWith('.md') ? rootLoc.substring(0, rootLoc.length() - 3) : rootLoc
        // normalize a bundle-relative concept path; resolves ./.. segments,
        // null = rejected (escapes the bundle root or has a scheme)
        def normPath = { String p ->
            if (p == null) return null
            String n = p.trim()
            if (!n || n.contains(':')) return null
            List parts = []
            for (seg in n.split('/')) {
                if (seg == '' || seg == '.') continue
                if (seg == '..') {
                    if (!parts) return null
                    parts.remove(parts.size() - 1)
                } else { parts.add(seg) }
            }
            if (!parts) return null
            n = parts.join('/')
            if (!n.endsWith('.md')) n = n + '.md'
            return n
        }
        def readConcept = { String rel ->
            try { return ec.resource.getLocationReference(bundleDirLoc + '/' + rel)?.getText() }
            catch (Exception e) { return null }
        }

        if (name == "okf_index") {
            String idx = readConcept('index.md')
            result = idx ?
                [content: [[type: "text", text: idx]], isError: false] :
                [content: [[type: "text", text: "OKF bundle '${spaceId}' has no index.md."]], isError: true]
            return
        }

        String rel = normPath(arguments?.path as String)
        if (rel == null) {
            result = [content: [[type: "text", text: "Invalid or missing 'path'. Use a bundle-relative path from okf_index, e.g. 'tables/OrderHeader.md'."]], isError: true]
            return
        }
        String conceptText = readConcept(rel)
        if (conceptText == null) {
            // broken links are allowed in OKF — degrade gracefully, don't error hard
            result = [content: [[type: "text", text: "Concept '${rel}' not found in bundle '${spaceId}' (broken links are permitted by the OKF spec). Use okf_index to see what exists."]], isError: false]
            return
        }

        if (name == "okf_load_concept") {
            result = [content: [[type: "text", text: conceptText]], isError: false]
            return
        }

        // okf_follow: resolve the concept's markdown links to navigable neighbours
        String conceptDir = rel.contains('/') ? rel.substring(0, rel.lastIndexOf('/')) : ''
        def seen = new LinkedHashSet()
        List lines = []
        def linkMatcher = (conceptText =~ /\[([^\]]*)\]\(([^)]+)\)/)
        while (linkMatcher.find()) {
            String label = linkMatcher.group(1)
            String target = linkMatcher.group(2).trim()
            if (target.startsWith('http://') || target.startsWith('https://') || target.startsWith('#')) continue
            if (!target.contains('.md')) continue
            // absolute = bundle-root-relative; otherwise relative to the concept's dir
            String tRel = target.startsWith('/') ? target.substring(1) :
                    (conceptDir ? conceptDir + '/' + target : target)
            tRel = normPath(tRel)
            if (tRel == null || !seen.add(tRel)) continue
            boolean exists = readConcept(tRel) != null
            lines.add("- ${tRel}${label ? ' — ' + label : ''}${exists ? '' : ' (missing: broken link, tolerated)'}")
        }
        String followTxt = lines.isEmpty() ?
                "Concept '${rel}' has no outgoing concept links." :
                "Concepts linked from '${rel}' (load one with okf_load_concept):\n" + lines.join('\n')
        result = [content: [[type: "text", text: followTxt]], isError: false]
        return
    }

    if (name == "moqui_search_services") {
        def query = arguments?.query?.toLowerCase()
        if (!query) throw new Exception("Missing query")
        // Use cached names: avoids getKnownServiceNames() filesystem scan + getServiceDefinition()
        // Groovy compilation on every call (which caused class loader deadlocks).
        // For parameter details, use moqui_get_service_details.
        List<String> allGroWerpNames = org.moqui.mcp.adapter.McpToolAdapter.getCachedGroWerpServiceNames(ec)
        def nameMatches = allGroWerpNames.findAll { it.toLowerCase().contains(query) }
        // Prepend domain-alias services whose name lacks the noun (orders/invoices/
        // shipments/payments/transactions are all listed via get#FinDoc).
        def aliasNames = domainAliasFor(query).findAll { !nameMatches.contains(it) }
        def matchedNames = (aliasNames + nameMatches).take(30)
        def findocHint = aliasNames
            ? "Orders, invoices, shipments, payments and transactions are 'financial documents' — list them with growerp.100.FinDocServices100.get#FinDoc (set docType e.g. 'order' and sales=true/false)."
            : null
        def txt = new groovy.json.JsonBuilder([
            total: matchedNames.size(),
            services: matchedNames.collect { [name: it] },
            hint: findocHint ?: (matchedNames.size() == 30
                ? "Showing first 30 matches. Narrow your query or use moqui_get_service_details for parameter info."
                : (matchedNames.isEmpty()
                    ? "No matches. Search by a single noun keyword (e.g. 'order', 'invoice', 'product') rather than a full or guessed service path. Only growerp.* services are callable."
                    : null))
        ]).toString()
        result = [content: [[type: "text", text: txt]], isError: false]
        return
    }

    if (name == "moqui_get_service_details") {
        def svcName = arguments?.serviceName
        if (!svcName) throw new Exception("Missing serviceName")
        svcName = resolveSvcName(svcName)
        def sd = ec.service.getServiceDefinition(svcName)
        if (!sd) {
            def sugg = suggestServices(svcName, 5)
            def hint = sugg ? " Did you mean: ${sugg.join(', ')}?"
                : " Use moqui_search_services to find valid names."
            throw new Exception("Unknown service: ${svcName}. Only growerp.* services are callable.${hint}")
        }
        def descNode = sd.serviceNode.first("description")
        def inParams = [:]
        sd.getInParameterNames().each { pName ->
            def p = sd.getInParameter(pName)
            if (p) {
                def pInfo = [type: p.attribute("type") ?: "String", required: p.attribute("required") == "true"]
                def pDescNode = p.first("description")
                if (pDescNode?.text) pInfo.description = pDescNode.text.trim()
                inParams[pName] = pInfo
            }
        }
        def outParams = [:]
        sd.getOutParameterNames().each { pName ->
            def p = sd.getOutParameter(pName)
            if (p) {
                def pInfo = [type: p.attribute("type") ?: "String"]
                def pDescNode = p.first("description")
                if (pDescNode?.text) pInfo.description = pDescNode.text.trim()
                outParams[pName] = pInfo
            }
        }
        def details = [
            service: svcName,
            description: descNode?.text?.trim() ?: null,
            inParameters: inParams,
            outParameters: outParams
        ]
        result = [content: [[type: "text", text: new groovy.json.JsonBuilder(details).toString()]], isError: false]
        return
    }

    // Fallback: check if it's a general Moqui service (non-screen-based tools)
    if (ec.service.isServiceDefined(name)) {
        def svcArgs = new LinkedHashMap(arguments ?: [:])
        svcArgs.remove('_adkConfigId')   // never forward the gate hint to the service
        def gate = applyGate(name, svcArgs)
        if (!gate.allowed) {
            result = [content: [[type: "text", text: gate.message ?: "Action not permitted"]],
                      isError: (gate.decision == 'blocked')]
            return
        }
        // Execute service with current user context
        def serviceResult = ec.service.sync().name(name).parameters(gate.args)
            .requireNewTransaction(true).call()
        def callErr = errorResultIfFailed()
        if (callErr != null) { result = callErr; return }
        recordResult(gate.logId, serviceResult)
        // Convert result to MCP format for general services
        result = [content: [[type: "text", text: new JsonBuilder(serviceResult).toString()]], isError: false]
        return
    }

    throw new Exception("Unknown tool name: ${name}")
} catch (Exception e) {
    isError = true
    // A failed nested service call leaves errors on the message facade,
    // which would mark THIS service as failed and drop the result map —
    // the client would get {} instead of the error text. Clear them so
    // the MCP error response below actually reaches the agent.
    ec.message.clearErrors()
    result = [
        content: [
            [
                type: "text",
                text: "Error executing tool ${name}: ${e.message}"
            ]
        ],
        isError: true
    ]

    ec.logger.error("MCP tool execution error", e)
} finally {
    // Send a simple notification about tool execution
    try {
        def servlet = ec.web?.getServletContext()?.getAttribute("enhancedMcpServlet")
        if (servlet && sessionId) {
            def notification = [
                method: "notifications/tool_execution",
                params: [
                    toolName: name,
                    executionTime: (System.currentTimeMillis() - startTime) / 1000.0,
                    success: !isError,
                    timestamp: System.currentTimeMillis()
                ]
            ]
            //servlet.queueNotification(sessionId, notification)
        }
    } catch (Exception e) {
        ec.logger.warn("Failed to send tool execution notification: ${e.message}")
    }
}

import org.moqui.context.ExecutionContext

ExecutionContext ec = context.ec
def userGroups = ec.user.getUserGroupIdSet().collect { it }
def availableResources = []

ec.logger.debug("MCP ResourcesList: Discovering entities for user groups: ${userGroups}")

// Use ArtifactAuthzCheckView to find all entities user has permission for
// This is the "Moqui Way" - rely on the security system to tell us what is accessible
def aacvList = ec.entity.find("moqui.security.ArtifactAuthzCheckView")
    .condition("userGroupId", userGroups)
    .condition("artifactTypeEnumId", "AT_ENTITY")
    .condition("authzActionEnumId", "AUTHZA_VIEW")
    .useCache(true)
    .disableAuthz()
    .list()

for (def aacv in aacvList) {
    def entityName = aacv.artifactName
    // Basic sanity check to ensure entity is actually defined
    if (ec.entity.isEntityDefined(entityName)) {
        def description = "Moqui entity: ${entityName}"
        if (entityName.contains("View")) {
            description = "Moqui ViewEntity: ${entityName}"
        }

        availableResources << [
            uri: "entity://${entityName}",
            name: entityName,
            description: description,
            mimeType: "application/json"
        ]
    }
}

// Add instructions resource for MCP_USER role
if (userGroups.contains("McpUser")) {
    availableResources << [
        uri: "moqui://mcp/instructions",
        name: "instructions",
        description: "MCP server usage instructions",
        mimeType: "text/plain"
    ]
}

result = [resources: availableResources]

import org.moqui.context.ExecutionContext
import groovy.json.JsonBuilder

ExecutionContext ec = context.ec
def startTime = System.currentTimeMillis()

// Handle special moqui://mcp/instructions resource
if (uri == "moqui://mcp/instructions") {
    // Try to load from wiki
    def instructionsText = null
    try {
        def wikiPage = ec.entity.find("moqui.resource.wiki.WikiPage")
            .condition("wikiSpaceId", "MCP_SERVICE_DOCS")
            .condition("pagePath", "root")
            .useCache(true)
            .one()

        if (wikiPage) {
            def wikiSpace = ec.entity.find("moqui.resource.wiki.WikiSpace")
                .condition("wikiSpaceId", wikiPage.wikiSpaceId)
                .one()

            if (wikiSpace) {
                def pageLocation = wikiSpace.rootPageLocation
                if (!pageLocation.endsWith('/')) pageLocation += '/'
                pageLocation += wikiPage.pagePath + '.md'

                def pageRef = ec.resource.getLocationReference(pageLocation)
                instructionsText = pageRef?.getText()
            }
        }
    } catch (Exception e) {
        ec.logger.debug("Could not load instructions from wiki: ${e.message}")
    }

    // Fallback to hardcoded instructions
    if (!instructionsText) {
        instructionsText = "This server provides access to GrowERP through MCP. Use moqui_search_services to find available services, moqui_get_service_details to learn required parameters, and moqui_execute_service to run them."
    }

    result = [
        content: [[
            uri: "moqui://mcp/instructions",
            mimeType: "text/plain",
            text: instructionsText
        ]],
        isError: false
    ]
    return
}

// Parse entity URI (format: entity://EntityName)
if (!uri.startsWith("entity://")) {
    throw new Exception("Invalid resource URI: ${uri}")
}

def entityName = uri.substring(9)

if (!ec.entity.isEntityDefined(entityName)) {
    throw new Exception("Entity not found: ${entityName}")
}

try {
    def entityDef = null
    try {
        def entityInfoList = ec.entity.getAllEntityInfo(-1, true)
        entityDef = entityInfoList.find { it.entityName == entityName }
    } catch (Exception e) {
        ec.logger.debug("Error getting detailed entity info: ${e.message}")
    }

    if (!entityDef) {
        entityDef = [
            entityName: entityName,
            packageName: entityName.contains('.') ? entityName.split('\\.')[0] : "",
            description: "Entity: ${entityName}",
            isViewEntity: entityName.contains('View'),
            allFieldInfoList: []
        ]
    }

    // Query entity data
    def entityList = ec.entity.find(entityName).limit(100).list()

    // Format response for MCP - create multiple content objects
    def contentList = []

    // Add main content with entity data as text
    contentList << [
        type: "text",
        text: new JsonBuilder([
            entityName: entityName,
            description: entityDef.description,
            packageName: entityDef.packageName,
            recordCount: entityList.size(),
            data: entityList
        ]).toString()
    ]

    def responseMap = [
        content: contentList,
        isError: false
    ]

    def jsonOutput = new JsonBuilder(responseMap).toString()

    // Size protection
    def maxResponseSize = 1024 * 1024 // 1MB
    if (jsonOutput.length() > maxResponseSize) {
         def truncatedList = entityList.take(10)
         responseMap.data = truncatedList
         responseMap.truncated = true
         responseMap.message = "Truncated to 10 records due to size."
         jsonOutput = new JsonBuilder(responseMap).toString()
    }

    result = [
        content: [[
            uri: uri,
            mimeType: "application/json",
            text: jsonOutput
        ]],
        isError: false
    ]

} catch (Exception e) {
    ec.logger.error("Error reading resource ${uri}", e)
    result = [isError: true, content: [[type:"text", text: e.message]]]
}

import org.moqui.impl.context.UserFacadeImpl.UserInfo

// Get current user information
def currentUser = ec.user.username
def currentUserId = ec.user.userId

// Try to get visit information if sessionId is provided
def visitInfo = null
if (sessionId) {
    try {
        ec.artifactExecution.disableAuthz()
        def adminUserInfo = ec.user.pushUser("ADMIN")
        try {
            def visit = ec.entity.find("moqui.server.Visit")
                .condition("visitId", sessionId)
                .one()

            if (visit) {
                visitInfo = [
                    visitId: visit.visitId,
                    userId: visit.userId,
                    fromDate: visit.fromDate,
                    lastUpdatedStamp: visit.lastUpdatedStamp
                ]
            }
        } finally {
            ec.user.popUser()
        }
        ec.artifactExecution.enableAuthz()
    } catch (Exception e) {
        // Log but don't fail the ping
        ec.logger.warn("Error getting visit info for sessionId ${sessionId}: ${e.message}")
    }
}

result = [
    timestamp: ec.user.getNowTimestamp(),
    status: "healthy",
    version: "2.1.0",
    sessionId: sessionId,
    currentUser: currentUser,
    currentUserId: currentUserId,
    visitInfo: visitInfo,
    architecture: "Visit-based sessions"
]

import org.moqui.context.ExecutionContext
import groovy.json.JsonSlurper

ExecutionContext ec = context.ec

ec.logger.info("MCP PromptsList: Listing prompts from wiki space MCP_PROMPTS")

def prompts = []

// Query all wiki pages in MCP_PROMPTS space
def wikiPageList = ec.entity.find("moqui.resource.wiki.WikiPage")
    .condition("wikiSpaceId", "MCP_PROMPTS")
    .useCache(true)
    .list()

for (def wp in wikiPageList) {
    // Try to load argument schema from DbResource
    def arguments = []
    try {
        // Build resourceId for arguments file (e.g., WIKI_MCP_GET_STARTED_ARGS)
        def argsResourceId = "WIKI_MCP_${wp.pagePath.toUpperCase().replace('-', '_')}_ARGS"
        def dbResource = ec.entity.find("moqui.resource.DbResource")
            .condition("resourceId", argsResourceId)
            .one()
        if (dbResource) {
            def dbResourceFile = ec.entity.find("moqui.resource.DbResourceFile")
                .condition("resourceId", argsResourceId)
                .one()
            if (dbResourceFile) {
                def jsonText = dbResourceFile.fileData?.getText()
                if (jsonText) {
                    arguments = new JsonSlurper().parseText(jsonText) ?: []
                }
            }
        }
    } catch (Exception e) {
        ec.logger.debug("Could not parse arguments for ${wp.pagePath}: ${e.message}")
    }

    prompts << [
        name: wp.pagePath,
        title: wp.pagePath.split('-').collect { it.capitalize() }.join(' '),
        description: "MCP prompt template",
        arguments: arguments
    ]
}

result = [prompts: prompts]

import org.moqui.context.ExecutionContext
import groovy.text.GStringTemplateEngine
import groovy.json.JsonSlurper
import groovy.json.JsonBuilder

ExecutionContext ec = context.ec

ec.logger.info("MCP PromptsGet: START v2.0 - Retrieving prompt '${name}' from wiki space MCP_PROMPTS")

// Debug: Check what wiki pages exist in MCP_PROMPTS space
def allPages = ec.entity.find("moqui.resource.wiki.WikiPage")
    .condition("wikiSpaceId", "MCP_PROMPTS")
    .useCache(true)
    .list()
ec.logger.info("MCP PromptsGet: All pages in MCP_PROMPTS space: ${allPages.collect { [pageId: it.wikiPageId, pagePath: it.pagePath] }}")

// Get the wiki page for this prompt
def wikiPage = ec.entity.find("moqui.resource.wiki.WikiPage")
    .condition("wikiSpaceId", "MCP_PROMPTS")
    .condition("pagePath", name)
    .useCache(true)
    .one()
ec.logger.info("MCP PromptsGet: Looking for pagePath='${name}', found: ${wikiPage?.wikiPageId}")

if (!wikiPage) {
    def available = allPages.collect { it.pagePath }.join(', ') ?: 'none'
    def svcHint = name?.contains('#')
        ? " '${name}' looks like a service name — prompts are documentation templates, not services; use moqui_search_services / moqui_execute_service instead."
        : ""
    throw new Exception("Prompt not found: ${name}. Available prompts: ${available}.${svcHint}")
}

// Get the wiki space to build the page location
def wikiSpace = ec.entity.find("moqui.resource.wiki.WikiSpace")
    .condition("wikiSpaceId", "MCP_PROMPTS")
    .useCache(true)
    .one()

if (!wikiSpace) {
    throw new Exception("MCP Prompts wiki space not found")
}

// Direct child-of-root-page location, same proven pattern as
// mcp#Initialize root instructions (findChildFile strips the root
// page's .md and looks in a sibling folder that does not exist)
def pageLocation = wikiSpace.rootPageLocation
if (!pageLocation.endsWith('/')) pageLocation += '/'
pageLocation += wikiPage.pagePath + '.md'
def pageRef = ec.resource.getLocationReference(pageLocation)
ec.logger.info("MCP PromptsGet: pageRef.location=${pageRef?.location}")

def templateText = pageRef?.getText()
ec.logger.info("MCP PromptsGet: templateText.length=${templateText?.length() ?: 'null'}")

if (!templateText) {
    throw new Exception("Prompt template not found: ${name}")
}

// Load arguments schema from DbResource for prompt metadata
def promptArguments = []
try {
    def argsResourceId = "WIKI_MCP_${name.toUpperCase().replace('-', '_')}_ARGS"
    def dbResource = ec.entity.find("moqui.resource.DbResource")
        .condition("resourceId", argsResourceId)
        .useCache(true)
        .one()
    if (dbResource) {
        def dbResourceFile = ec.entity.find("moqui.resource.DbResourceFile")
            .condition("resourceId", argsResourceId)
            .useCache(true)
            .one()
        if (dbResourceFile) {
            def fd = dbResourceFile.fileData
            def jsonText = fd instanceof java.sql.Blob
                ? new String(fd.getBytes(1L, (int) fd.length()), "UTF-8")
                : (fd instanceof byte[] ? new String(fd, "UTF-8") : fd?.toString())
            if (jsonText) {
                promptArguments = new JsonSlurper().parseText(jsonText) ?: []
            }
        }
    }
} catch (Exception e) {
    ec.logger.debug("Could not parse arguments for ${name}: ${e.message}")
}

// Render template using Groovy GString engine
def templateEngine = new GStringTemplateEngine()
def template = templateEngine.createTemplate(templateText)
// withDefault: template placeholders the caller didn't supply render as
// null instead of throwing MissingPropertyException
def binding = new HashMap(arguments ?: [:]).withDefault { null }
def rendered = template.make(binding).toString()

ec.logger.info("MCP PromptsGet: Rendered prompt '${name}' with ${binding.size()} arguments")

result = [
    description: "MCP prompt template",
    arguments: promptArguments,
    messages: [[
        role: "user",
        content: [type: "text", text: rendered]
    ]]
]

import org.moqui.context.ExecutionContext
import org.moqui.util.RestClient
import groovy.json.JsonBuilder

ExecutionContext ec = context.ec

def errorResult = { String msg ->
    return [content: [[type: "text", text: msg]], isError: true]
}

// ── 1. SystemSupport-only guard (username, never a password literal) ──
String allowedUser = System.getProperty("moqui.mcp.rest.allowed.username", "SystemSupport")
if (ec.user.username != allowedUser) {
    result = errorResult("REST API access is restricted to the ${allowedUser} account (current user: ${ec.user.username ?: 'anonymous'}).")
    return
}

// ── 2. Require the inbound Basic auth credential to forward (no embedded fallback) ──
String authHdr = null
try { authHdr = ec.web?.getRequest()?.getHeader('Authorization') } catch (ignore) {}
if (!authHdr) {
    result = errorResult("No inbound Authorization credential available to forward to the REST API.")
    return
}

// ── 3. Normalise path: strip leading slash and optional 'rest/' prefix; GET only ──
String relPath = (path ?: "").trim()
while (relPath.startsWith("/")) relPath = relPath.substring(1)
if (relPath.toLowerCase().startsWith("rest/")) relPath = relPath.substring(5)
if (!relPath) { result = errorResult("Empty REST path."); return }

// ── 4. Build URL: base + /rest/ + path + encoded query string ──
String baseUrl = System.getProperty("moqui.mcp.rest.base.url", "http://localhost:8080")
while (baseUrl.endsWith("/")) baseUrl = baseUrl.substring(0, baseUrl.length() - 1)
StringBuilder urlSb = new StringBuilder(baseUrl).append("/rest/").append(relPath)
if (queryParameters instanceof Map && !queryParameters.isEmpty()) {
    urlSb.append(relPath.contains("?") ? "&" : "?")
    boolean first = true
    queryParameters.each { k, v ->
        if (v == null) return
        if (!first) urlSb.append("&")
        urlSb.append(java.net.URLEncoder.encode(k.toString(), "UTF-8"))
           .append("=").append(java.net.URLEncoder.encode(v.toString(), "UTF-8"))
        first = false
    }
}
String url = urlSb.toString()

// ── 5. Loopback GET, forwarding the caller's credential ──
try {
    RestClient rc = ec.service.rest().method(RestClient.GET).uri(url)
    rc.addHeader("Authorization", authHdr)
    rc.addHeader("Accept", "application/json")
    RestClient.RestResponse resp = rc.call()
    int sc = resp.statusCode

    Object body
    try { body = resp.jsonObject() } catch (Exception je) { body = resp.text() }

    if (sc < 200 || sc >= 300) {
        result = [content: [[type: "text", text: new JsonBuilder([
                statusCode: sc, error: true, path: relPath, response: body]).toString()]],
                isError: true]
    } else {
        result = [content: [[type: "text", text: new JsonBuilder([
                statusCode: sc, path: relPath, response: body]).toString()]],
                isError: false]
    }
} catch (Exception e) {
    ec.logger.warn("moqui_rest_call GET ${url} failed: ${e.message}")
    result = errorResult("REST call failed for path '${relPath}': ${e.message}")
}

import org.moqui.context.ExecutionContext
import groovy.json.JsonBuilder

ExecutionContext ec = context.ec

def content = null
def metadata = [uri: uri]

// Parse URI format: wiki:type:name
// e.g., wiki:service:ProductFeature, wiki:workflow:Order-Entry
if (uri?.startsWith("wiki:")) {
    def parts = uri.split(":", 3)
    if (parts.length >= 3) {
        def wikiType = parts[1]  // service, workflow
        def pageName = parts[2]

        metadata.type = wikiType
        metadata.name = pageName

        // Moqui screens are not used in GrowERP (Flutter frontend)
        if (wikiType == "screen") {
            result = [
                content: [[type: "text", text: new JsonBuilder([
                    content: "Moqui screens are not used in this GrowERP deployment; there is no screen documentation. Use 'wiki:service:<Name>' or 'wiki:workflow:<Name>' (e.g. 'wiki:workflow:Order-Entry') instead.",
                    metadata: metadata]).toString()]],
                isError: false
            ]
            return
        }

        // Determine wiki space based on type
        def wikiSpaceId = null
        def pagePath = null

        switch (wikiType) {
            case "service":
                wikiSpaceId = "MCP_SERVICE_DOCS"
                pagePath = pageName
                break
            case "workflow":
                wikiSpaceId = "BUSINESS_PROCESSES"
                pagePath = pageName
                break
            default:
                wikiSpaceId = "MCP_SERVICE_DOCS"
                pagePath = pageName
        }

        // Try to find wiki page by path
        def wikiPage = ec.entity.find("moqui.resource.wiki.WikiPage")
            .condition("wikiSpaceId", wikiSpaceId)
            .condition("pagePath", pagePath)
            .useCache(true)
            .one()

        // If not found by exact path, try partial match
        if (!wikiPage) {
            def allPages = ec.entity.find("moqui.resource.wiki.WikiPage")
                .condition("wikiSpaceId", wikiSpaceId)
                .useCache(true)
                .list()
            wikiPage = allPages.find { it.pagePath?.endsWith(pagePath) || it.pagePath?.contains(pagePath) }
        }

        if (wikiPage) {
            // Use direct DbResource/DbResourceFile lookup
            def parentResourceId
            switch (wikiType) {
                case "workflow":
                    parentResourceId = "WIKI_BUSINESS_PROCESSES"
                    break
                default:
                    parentResourceId = "WIKI_MCP_SERVICE_DOCS"
            }

            def dbResource = ec.entity.find("moqui.resource.DbResource")
                .condition("parentResourceId", parentResourceId)
                .condition("filename", wikiPage.pagePath + ".md")
                .one()



            if (dbResource) {
                def dbResourceFile = ec.entity.find("moqui.resource.DbResourceFile")
                    .condition("resourceId", dbResource.resourceId)
                    .condition("versionName", wikiPage.publishedVersionName)
                    .one()

                if (!dbResourceFile) {
                    dbResourceFile = ec.entity.find("moqui.resource.DbResourceFile")
                        .condition("resourceId", dbResource.resourceId)
                        .one()
                }

                if (dbResourceFile && dbResourceFile.fileData) {
                    content = new String(dbResourceFile.fileData.getBytes(new Long(1).longValue(), new Long(dbResourceFile.fileData.length()).intValue()), "UTF-8")
                    metadata.found = true
                    metadata.pagePath = wikiPage.pagePath
                    metadata.resourceId = dbResource.resourceId
                }
            }
        }

        if (!content) {
            metadata.found = false
            content = "No documentation found for ${wikiType}: ${pageName}. Available documentation is in the MCP_SERVICE_DOCS (wiki:service:*) and BUSINESS_PROCESSES (wiki:workflow:*) wiki spaces."
        }
    }
} else {
    metadata.error = "Invalid URI format. Expected 'wiki:type:name' (e.g., 'wiki:service:ProductFeature' or 'wiki:workflow:Order-Entry')"
    content = metadata.error
}

def resultData = [
    content: content,
    metadata: metadata
]

result = [
    content: [[type: "text", text: new JsonBuilder(resultData).toString()]],
    isError: false
]
